"""DataFlowCategory — the free category generated by program operations.

From category theory, the data flow of a program forms a small category:

    Objects  = typed contexts (block_id, {var → Sort})
    Morphisms = TypedOp applications transforming one context to another
    Composition = sequential application (checked for sort compatibility)
    Identity = no-op at each context

This category is the *site* on which we define the type presheaf and
compute Čech cohomology.  Its nerve gives the simplicial complex that
is the topological space underlying the motive.

The fundamental groupoid π₁(D_f) of this category captures the loop
structure of the program (from homotopy type theory).
"""

from __future__ import annotations

from dataclasses import dataclass, field
from typing import Dict, FrozenSet, List, Optional, Set, Tuple

from deppy.motive.sorts import Sort, sorts_compatible
from deppy.motive.operations import TypedOp, FlowEdge, Effect
from deppy.motive.fiber import TypeFiber, FiberMorphism


@dataclass
class CategoryObject:
    """An object in the data flow category — a typed program context."""
    block_id: int
    context: Dict[str, Sort] = field(default_factory=dict)
    fiber: TypeFiber = field(default_factory=TypeFiber.empty)

    @property
    def context_key(self) -> FrozenSet[Tuple[str, Sort]]:
        return frozenset(self.context.items())


@dataclass
class CategoryMorphism:
    """A morphism in the data flow category — a typed operation."""
    source: int          # source object index
    target: int          # target object index
    operation: TypedOp   # the operation applied
    edge: FlowEdge      # the underlying flow edge

    @property
    def is_loop(self) -> bool:
        """True if this is a back-edge (loop in π₁)."""
        return self.source == self.target

    @property
    def is_identity(self) -> bool:
        return self.operation.name == 'Id'


@dataclass
class DataFlowCategory:
    """The free category generated by the program's data flow.

    This is the central mathematical object from which the motive
    is computed.  It integrates:

    1. Objects — typed program states (from dependent type theory)
    2. Morphisms — operations between states (from Lawvere theory)
    3. Composition — checked for sort compatibility
    4. Loop detection — for the fundamental groupoid (from HoTT)

    The Grothendieck topology on this category is the one where
    covers are generated by basic block decompositions.
    """
    objects: List[CategoryObject] = field(default_factory=list)
    morphisms: List[CategoryMorphism] = field(default_factory=list)

    # ── Construction ──

    def add_object(self, block_id: int, context: Dict[str, Sort],
                   fiber: TypeFiber) -> int:
        """Add an object (typed context) and return its index."""
        idx = len(self.objects)
        self.objects.append(CategoryObject(
            block_id=block_id, context=dict(context), fiber=fiber,
        ))
        return idx

    def add_morphism(self, source: int, target: int,
                     operation: TypedOp, edge: FlowEdge) -> int:
        """Add a morphism (operation) and return its index."""
        idx = len(self.morphisms)
        self.morphisms.append(CategoryMorphism(
            source=source, target=target, operation=operation, edge=edge,
        ))
        return idx

    # ── Category structure ──

    def compose(self, f_idx: int, g_idx: int) -> Optional[CategoryMorphism]:
        """Compose morphisms f;g (f then g).

        Returns None if composition is undefined (cod(f) ≠ dom(g)).
        """
        f = self.morphisms[f_idx]
        g = self.morphisms[g_idx]
        if f.target != g.source:
            return None
        return CategoryMorphism(
            source=f.source,
            target=g.target,
            operation=TypedOp(
                name=f'{f.operation.name};{g.operation.name}',
                input_sorts=f.operation.input_sorts,
                output_sort=g.operation.output_sort,
                refinements=f.operation.refinements & g.operation.refinements,
                effect=max(f.operation.effect, g.operation.effect),
            ),
            edge=FlowEdge(
                source_block=f.edge.source_block,
                target_block=g.edge.target_block,
                source_sort=f.edge.source_sort,
                target_sort=g.edge.target_sort,
                op_index=-1,
            ),
        )

    # ── Topological invariants ──

    def connected_components(self) -> int:
        """Number of connected components (π₀ from HoTT)."""
        if not self.objects:
            return 0
        n = len(self.objects)
        parent = list(range(n))

        def find(x: int) -> int:
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(x: int, y: int) -> None:
            px, py = find(x), find(y)
            if px != py:
                parent[px] = py

        for m in self.morphisms:
            if 0 <= m.source < n and 0 <= m.target < n:
                union(m.source, m.target)

        return len(set(find(i) for i in range(n)))

    def loops(self) -> List[CategoryMorphism]:
        """All back-edges (loops) — generators of π₁."""
        return [m for m in self.morphisms if m.is_loop]

    def cycle_rank(self) -> int:
        """Rank of the fundamental groupoid π₁.

        From algebraic topology: rank π₁ = |edges| - |vertices| + components.
        This is the first Betti number of the data flow graph.
        """
        n = len(self.objects)
        e = len(self.morphisms)
        c = self.connected_components()
        return max(0, e - n + c)

    def adjacency_multiset(self) -> Dict[Tuple[int, int], List[TypedOp]]:
        """Adjacency structure as multiset of operations per edge."""
        adj: Dict[Tuple[int, int], List[TypedOp]] = {}
        for m in self.morphisms:
            key = (m.source, m.target)
            adj.setdefault(key, []).append(m.operation)
        return adj

    def out_degree(self, obj_idx: int) -> int:
        """Number of outgoing morphisms from an object."""
        return sum(1 for m in self.morphisms if m.source == obj_idx)

    def in_degree(self, obj_idx: int) -> int:
        """Number of incoming morphisms to an object."""
        return sum(1 for m in self.morphisms if m.target == obj_idx)

    # ── Fiber morphisms (presheaf structure maps) ──

    def fiber_morphisms(self) -> List[FiberMorphism]:
        """Compute the fiber morphisms induced by all morphisms.

        This is the data that defines the type presheaf:
        each morphism f: A→B induces a fiber morphism F(B)→F(A).
        """
        result = []
        for m in self.morphisms:
            if 0 <= m.source < len(self.objects) and 0 <= m.target < len(self.objects):
                src_fiber = self.objects[m.source].fiber
                tgt_fiber = self.objects[m.target].fiber
                result.append(FiberMorphism.from_operation(src_fiber, tgt_fiber, m.operation))
        return result

    # ── Galois symmetry (from Galois theory) ──

    def automorphism_count_upper_bound(self) -> int:
        """Upper bound on |Aut(D_f)| — the symmetry group size.

        From Galois theory: the automorphism group of the data flow graph
        captures the computational symmetries.  Two equivalent programs
        should have automorphism groups of the same order.
        """
        from collections import Counter
        # Group objects by their sort profile
        profiles = Counter()
        for obj in self.objects:
            profile = frozenset(obj.context.items()) if obj.context else frozenset()
            profiles[profile] += 1
        # Upper bound: product of factorials of group sizes
        result = 1
        for count in profiles.values():
            for i in range(1, count + 1):
                result *= i
                if result > 10000:
                    return 10000  # cap to avoid overflow
        return result
